    /**
     * Keep the /suspended/ landing page draft while the store is active so it does not appear in menus.
     * Publish only when suspended so guest redirects still resolve.
     */
    private static function sync_suspended_page_visibility(): void
    {
        $page = get_page_by_path('suspended');
        $desired_status = self::is_suspended() ? 'publish' : 'draft';

        if (!$page instanceof WP_Post) {
            wp_insert_post([
                'post_title' => 'Store Temporarily Unavailable',
                'post_name' => 'suspended',
                'post_content' => 'This store is temporarily unavailable. Please contact support.',
                'post_status' => $desired_status,
                'post_type' => 'page',
            ]);

            return;
        }

        if ($page->post_status !== $desired_status) {
            wp_update_post([
                'ID' => $page->ID,
                'post_status' => $desired_status,
            ]);
        }
    }
}

