    /**
     * @return int Attachment ID or 0
     */
    private static function sideload_image_to_media(string $url, string $title): int
    {
        if ($url === '' || !wp_http_validate_url($url)) {
            return 0;
        }

        require_once ABSPATH . 'wp-admin/includes/file.php';
        require_once ABSPATH . 'wp-admin/includes/media.php';
        require_once ABSPATH . 'wp-admin/includes/image.php';

        $prev_user = get_current_user_id();
        $admin_id = self::first_blog_administrator_id();
        if ($admin_id > 0) {
            wp_set_current_user($admin_id);
        }

        try {
            $tmp = download_url($url);
            if (is_wp_error($tmp)) {
                return 0;
            }

            $path = wp_parse_url($url, PHP_URL_PATH);
            $basename = $path ? sanitize_file_name(basename((string) $path)) : 'image.png';
            if ($basename === '' || $basename === '.') {
                $basename = 'image.png';
            }

            $file_array = [
                'name' => $basename,
                'tmp_name' => $tmp,
            ];

            $id = media_handle_sideload($file_array, 0, $title);

            if (is_wp_error($id)) {
                @unlink($tmp);

                return 0;
            }

            return (int) $id;
        } finally {
            wp_set_current_user($prev_user);
        }
    }

    private static function first_blog_administrator_id(): int
    {
        $admins = get_users([
            'blog_id' => get_current_blog_id(),
            'role' => 'administrator',
            'number' => 1,
            'orderby' => 'ID',
            'order' => 'ASC',
            'fields' => 'ID',
        ]);

        if (!empty($admins[0])) {
            return (int) $admins[0];
        }

        return (int) get_current_blog_id() === 1 ? 1 : 0;
    }
}

