/**
 * Permanently removes a tenant subsite (drops tables). Same HMAC auth as provision-store.
 */
public static function delete_store(WP_REST_Request $request): WP_REST_Response
{
    require_once ABSPATH . 'wp-admin/includes/ms.php';

    $payload = $request->get_json_params();
    $request_id = isset($payload['request_id']) ? sanitize_key((string) $payload['request_id']) : '';

    if ($request_id !== '') {
        $existing_delete = self::find_existing_delete_by_request_id($request_id);
        if (!empty($existing_delete['deleted_at'])) {
            return new WP_REST_Response([
                'success' => true,
                'idempotent' => true,
                'site_id' => (int) ($existing_delete['site_id'] ?? 0),
                'tenant_slug' => (string) ($existing_delete['tenant_slug'] ?? ''),
            ], 200);
        }
    }

    if (empty($payload['tenant_slug'])) {
        return new WP_REST_Response([
            'success' => false,
            'error' => 'Missing required field: tenant_slug',
        ], 422);
    }

    $tenant_slug = sanitize_title((string) $payload['tenant_slug']);
    $slug_validation = self::validate_tenant_slug($tenant_slug);
    if (!$slug_validation['valid']) {
        return new WP_REST_Response([
            'success' => false,
            'error' => (string) $slug_validation['error'],
        ], 422);
    }

    $domain = self::tenant_domain($tenant_slug);
    $blog_id = (int) get_blog_id_from_url($domain, '/');

    if ($blog_id === 0) {
        return new WP_REST_Response([
            'success' => true,
            'already_deleted' => true,
            'tenant_slug' => $tenant_slug,
        ], 200);
    }

    if ($blog_id === 1 || is_main_site($blog_id)) {
        return new WP_REST_Response([
            'success' => false,
            'error' => 'Cannot delete the main network site',
        ], 403);
    }

    wpmu_delete_blog($blog_id, true);

    $response_data = [
        'success' => true,
        'site_id' => $blog_id,
        'tenant_slug' => $tenant_slug,
    ];

    if ($request_id !== '') {
        self::store_delete_request_id_mapping($request_id, $response_data);
    }

    return new WP_REST_Response($response_data, 200);
}

private static function delete_idempotency_option_key(string $request_id): string
{
    return self::DELETE_IDEMPOTENCY_OPTION_PREFIX . md5($request_id);
}

private static function find_existing_delete_by_request_id(string $request_id): array
{
    $key = self::delete_idempotency_option_key($request_id);
    $value = get_site_option($key, []);

    return is_array($value) ? $value : [];
}

private static function store_delete_request_id_mapping(string $request_id, array $response_data): void
{
    $key = self::delete_idempotency_option_key($request_id);
    update_site_option($key, [
        'site_id' => (int) ($response_data['site_id'] ?? 0),
        'tenant_slug' => (string) ($response_data['tenant_slug'] ?? ''),
        'deleted_at' => current_time('mysql'),
    ]);
}

