/**
 * Network-default favicon shipped with printonet-core (override via provision favicon_url).
 */
private static function apply_bundle_default_site_icon(): void
{
    $path = PRINTONET_CORE_PATH . '/assets/favicon.ico';
    if (!is_readable($path)) {
        return;
    }

    $id = self::import_local_media_file($path, 'Printonet favicon', 'favicon.ico');
    if ($id > 0) {
        update_option('site_icon', $id);
    }
}

/**
 * @return int Attachment ID or 0
 */
private static function import_local_media_file(string $absolute_path, string $title, string $download_name): int
{
    require_once ABSPATH . 'wp-admin/includes/file.php';
    require_once ABSPATH . 'wp-admin/includes/media.php';
    require_once ABSPATH . 'wp-admin/includes/image.php';

    $prev_user = get_current_user_id();
    $admin_id = self::first_blog_administrator_id();
    if ($admin_id > 0) {
        wp_set_current_user($admin_id);
    }

    $tmp = wp_tempnam($download_name);
    if (!$tmp || !copy($absolute_path, $tmp)) {
        if ($tmp) {
            @unlink($tmp);
        }
        wp_set_current_user($prev_user);

        return 0;
    }

    $allow_ico = static function (array $mimes): array {
        $mimes['ico'] = 'image/x-icon';

        return $mimes;
    };
    add_filter('upload_mimes', $allow_ico);

    try {
        $file_array = [
            'name' => sanitize_file_name($download_name),
            'tmp_name' => $tmp,
        ];
        $id = media_handle_sideload($file_array, 0, $title);

        if (is_wp_error($id)) {
            @unlink($tmp);

            return 0;
        }

        return (int) $id;
    } finally {
        remove_filter('upload_mimes', $allow_ico);
        wp_set_current_user($prev_user);
    }
}

