/**
 * Blockified Product Catalog (WooCommerce default) renders <!-- wp:query-title type:archive /-->
 * — it never touches PHP loop/header.php, so strip it on product archives only.
 */
add_filter('render_block', static function ($block_content, array $block) {
    if (($block['blockName'] ?? '') !== 'core/query-title') {
        return $block_content;
    }

    $atype = $block['attrs']['type'] ?? '';
    if ($atype !== 'archive') {
        return $block_content;
    }

    if (!function_exists('is_shop')) {
        return $block_content;
    }

    if (!is_shop() && !is_product_taxonomy()) {
        return $block_content;
    }

    return '';
}, 10, 2);

